def recommend_model(requirements: dict) -> dict:
    needs_privacy = requirements.get('on_premise', False) or requirements.get('hipaa', False)
    budget = requirements.get('monthly_budget_usd', 9999999)
    modalities = requirements.get('modalities', ['text'])

    if needs_privacy:
        return {
            'model': 'Llama-3.3-70B-Instruct-Q4',
            'provider': 'Meta (self-hosted)',
            'rationale': 'HIPAA requires on-premise data processing; open weights allow local deployment',
            'estimated_cost': '$2,800/month (2x A100 80GB on AWS)',
            'risks': ['Self-managed uptime', 'Quantization may reduce accuracy slightly', 'Need MLOps expertise']
        }
    elif budget < 500:
        return {
            'model': 'gpt-3.5-turbo or claude-haiku',
            'provider': 'OpenAI / Anthropic',
            'rationale': 'Low cost per token, managed infrastructure, sufficient for most chat tasks',
            'estimated_cost': '<$100/month at moderate volume',
            'risks': ['Data sent to vendor', 'Less capable than frontier models']
        }
    else:
        return {
            'model': 'claude-sonnet-4-6 or gpt-4o',
            'provider': 'Anthropic / OpenAI',
            'rationale': 'Frontier capability, managed infrastructure, best reasoning quality',
            'estimated_cost': '$500-5000/month depending on volume',
            'risks': ['Data sent to vendor', 'Higher per-token cost']
        }

