import math

def apply_temperature(logits: dict[str, float], temperature: float) -> dict[str, float]:
    if temperature <= 0:
        raise ValueError('Temperature must be positive')
    scaled = {t: s / temperature for t, s in logits.items()}
    max_val = max(scaled.values())
    exp_scores = {t: math.exp(s - max_val) for t, s in scaled.items()}
    total = sum(exp_scores.values())
    return {t: v / total for t, v in exp_scores.items()}
